// // When kb is 00, a should be 1; when kb is 11, a should be 0; when kb is 01, a should be 1; when kb is 10, a should be 0.
module top_module (
    input k,
    input b,
    output reg a
);
    always @(*) begin
        case ({k, b})
            2'b00: a = 1'b0;
            2'b11: a = 1'b1;
            2'b01: a = 1'b0;
            2'b10: a = 1'b1;
        endcase
    end
endmodule
